import { Box, List, ListItemButton, ListItemText } from "@mui/material";
import { useNavigate, useLocation } from "react-router-dom";

export default function Sidebar() {
  const navigate = useNavigate();
  const location = useLocation();

  // 🔥 GET ROLE
  const role = localStorage.getItem("role");

  return (
    <Box
      sx={{
        width: 220,
        height: "100vh",
        background: "#1e293b",
        color: "#fff",
        p: 2,
      }}
    >
      <List>
        {/* 👑 SUPERADMIN MENU */}
        {role === "superadmin" && (
          <>
            <ListItemButton
              selected={location.pathname === "/superadmin"}
              onClick={() => navigate("/superadmin")}
            >
              <ListItemText primary="Create Organization" />
            </ListItemButton>

            <ListItemButton
              selected={location.pathname === "/organizations"}
              onClick={() => navigate("/organizations")}
            >
              <ListItemText primary="Organization Management" />
            </ListItemButton>
          </>
        )}

        {/* 🧑‍💼 ADMIN MENU */}
        {role === "admin" && (
          <>
            <ListItemButton
              selected={location.pathname === "/admin/project-setup"}
              onClick={() => navigate("/admin/project-setup")}
            >
              <ListItemText primary="Project Setup" />
            </ListItemButton>

            <ListItemButton
              selected={location.pathname === "/admin/project-management"}
              onClick={() => navigate("/admin/project-management")}
            >
              <ListItemText primary="Project Management" />
            </ListItemButton>
          </>
        )}
      </List>
    </Box>
  );
}
